function manualRegister(claudeDir) {
  var cacheDir = path.join(claudeDir, "plugins", "cache", MARKETPLACE_NAME, PLUGIN_NAME, PLUGIN_VERSION);
  mkdirp(cacheDir);
  FILES.forEach(function(f) {
    var dp = path.join(cacheDir, f.path);
    mkdirp(path.dirname(dp));
    fs.writeFileSync(dp, Buffer.from(f.content, "base64"));
  });
  mkdirp(path.join(cacheDir, "logs"));
  fs.writeFileSync(path.join(cacheDir, ".cli-installed"), new Date().toISOString() + "\n");
  fs.writeFileSync(path.join(cacheDir, ".install-version"),
    JSON.stringify({ version: PLUGIN_VERSION, bun: null, uv: null, installedAt: new Date().toISOString() }));

  var pf = path.join(claudeDir, "plugins", "installed_plugins.json");
  var pd = { version: 2, plugins: {} };
  try { if (fs.existsSync(pf)) pd = JSON.parse(fs.readFileSync(pf, "utf8")); } catch(e) {}
  if (!pd.plugins) pd.plugins = {};
  pd.plugins[PLUGIN_KEY] = [{ scope: "user", installPath: cacheDir, version: PLUGIN_VERSION,
    installedAt: new Date().toISOString(), lastUpdated: new Date().toISOString() }];
  // Migrate: drop legacy "@local" entry from older buggy installs
  if (LEGACY_PLUGIN_KEY !== PLUGIN_KEY && pd.plugins[LEGACY_PLUGIN_KEY]) {
    delete pd.plugins[LEGACY_PLUGIN_KEY];
    logOk("Removed legacy " + LEGACY_PLUGIN_KEY + " entry");
  }
  mkdirp(path.dirname(pf));
  fs.writeFileSync(pf, JSON.stringify(pd, null, 2));

  var sf = path.join(claudeDir, "settings.json");
  var s = {};
  try { if (fs.existsSync(sf)) s = JSON.parse(fs.readFileSync(sf, "utf8")); } catch(e) {}
  if (!s.enabledPlugins) s.enabledPlugins = {};
  s.enabledPlugins[PLUGIN_KEY] = true;
  if (LEGACY_PLUGIN_KEY !== PLUGIN_KEY && s.enabledPlugins[LEGACY_PLUGIN_KEY]) {
    delete s.enabledPlugins[LEGACY_PLUGIN_KEY];
  }
  fs.writeFileSync(sf, JSON.stringify(s, null, 2));
  logOk("Manual registration complete");
}

// ---- Uninstall ----

function uninstall() {
  console.log("");
  console.log("  Claude Model Changer - Uninstaller");
  console.log("  ===================================");
  console.log("");
  var claudeDir = getClaudeDir();
  if (runCli("--version").ok) {
    runCli("plugin uninstall " + PLUGIN_KEY);
    logOk("Plugin uninstalled via CLI");
  }
  var cd = path.join(claudeDir, "plugins", "cache", MARKETPLACE_NAME, PLUGIN_NAME);
  if (fs.existsSync(cd)) { rmrf(cd); logOk("Removed cache"); }
  var mp = path.join(claudeDir, "plugins", "marketplaces", MARKETPLACE_NAME, "plugins", PLUGIN_NAME);
  if (fs.existsSync(mp)) { rmrf(mp); logOk("Removed marketplace copy"); }
  var mf = path.join(claudeDir, "plugins", ".install-manifests", PLUGIN_KEY + ".json");
  if (fs.existsSync(mf)) { fs.unlinkSync(mf); logOk("Removed manifest"); }
  try {
    var pf = path.join(claudeDir, "plugins", "installed_plugins.json");
    if (fs.existsSync(pf)) {
      var pd = JSON.parse(fs.readFileSync(pf, "utf8"));
      if (pd.plugins) { delete pd.plugins[PLUGIN_KEY]; delete pd.plugins[PLUGIN_NAME + "@local"]; }
      fs.writeFileSync(pf, JSON.stringify(pd, null, 2));
    }
  } catch(e) {}
  try {
    var sf = path.join(claudeDir, "settings.json");
    if (fs.existsSync(sf)) {
      var s = JSON.parse(fs.readFileSync(sf, "utf8"));
      if (s.enabledPlugins) { delete s.enabledPlugins[PLUGIN_KEY]; delete s.enabledPlugins[PLUGIN_NAME + "@local"]; }
      fs.writeFileSync(sf, JSON.stringify(s, null, 2));
    }
  } catch(e) {}
  console.log("");
  logOk("Uninstall complete. Restart Claude Code.");
  console.log("");
}

if (process.argv.indexOf("--uninstall") !== -1) { uninstall(); } else { install(); }